#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=2e3+5;
int f[3][MAXN][MAXN],cnt[MAXN],n,m;
char s[105][15];
vector<int> v[105];
bool check(int n,int m,int x)
{
	for(int i=0;i<m;++i)
    {
		if(s[n][i]=='H'&&((x>>i)&1))
		{
		    return false;
        }
	}
	int pos=-3;
	for(int i=0;i<m;++i)
    {
		if((x>>i)&1)
        {
			if((i-pos)<3)
            {
                return false;
            }
			pos=i;
		}
	}
	return true;
}
int zero(int n)
{
	int ans=0;
	while(n)
    {
		if(n&1)
        {
            ++ans;
        }
		n>>=1;
	}
	return ans;
}
void init(int n)
{
	for(int i=0;i<n;++i)
    {
		cnt[i]=zero(i);
	}
}
int main(void)
{
	init(1<<10);
	memset(f,0,sizeof(f));
	n=read(),m=read();
	for(int i=0;i<n;++i)
    {
		scanf("%s",s[i]);
		for(int j=0;j<(1<<m);++j)
        {
			if(check(i,m,j))
            {
                v[i].push_back(j);
            }
		}
	}
	for(int i=0;i<n;++i)
    {
		for(int j=0;j<(int)v[i].size();++j)
        {
			if(i)
            {

				if(i==1)
                {
					for(int x=0;x<(int)v[i-1].size();++x)
                    {
						if((v[i][j]&v[i-1][x])==0)
                        {
							f[i%3][v[i][j]][v[i-1][x]]=max(f[i%3][v[i][j]][v[i-1][x]],f[(i-1)%3][v[i-1][x]][0]+cnt[v[i][j]]);
						}
					}
				}
				else
                {
					for(int x=0;x<(int)v[i-1].size();++x)
                    {
						if((v[i][j]&v[i-1][x])==0)
						{
						    for(int y=0;y<(int)v[i-2].size();++y)
                            {
								if((v[i-2][y]&v[i][j])==0&&(v[i-1][x]&v[i-2][y])==0&&(v[i][j]&(v[i-1][x]|v[i-2][y]))==0)
                                {
									f[i%3][v[i][j]][v[i-1][x]]=max(f[i%3][v[i][j]][v[i-1][x]],f[(i-1)%3][v[i-1][x]][v[i-2][y]]+cnt[v[i][j]]);
								}
							}
                        }
					}
				}
			}

			else
            {
				if(!i)
                {
					f[i][v[i][j]][0]=cnt[v[i][j]];
				}
			}
		}
	}
	int ans=0;
	for(int i=0;i<3;++i)
    {
		for(int x=0;x<(1<<m);++x)
        {
			for(int y=0;y<(1<<m);++y)
            {
				ans=max(ans,f[i][x][y]);
			}
		}
	}
	write(ans);
	return false;
}
